            j = this._idx.getLsbIndex(tmp[i - 1], garlic);
            this._hPrime.update(this.helper.concateByteArrays(tmp[i - 1], tmp[j]));
            tmp[i] = this._hPrime.doFinal();
            this._hPrime.reset();
            ++i;
